import React, { useState, useEffect } from 'react';
import Sidebar from './Sidebar';
import MessageArea from './MessageArea';
import InputArea from './InputArea';
import SuggestionChips from './SuggestionChips';
import { useTheme } from '../../hooks/useTheme';
import { useChat } from '../../hooks/useChat';
import { useChatHistory } from '../../hooks/useChatHistory';
import '../../styles/chat-interface.css';

const ChatInterface = () => {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(true);
  const { theme, toggleTheme } = useTheme();
  
  const {
    messages,
    inputMessage,
    setInputMessage,
    isLoading,
    isTyping,
    sendMessage,
    clearChat,
    sessionId
  } = useChat();

  const {
    chatHistory,
    saveChatSession,
    loadChatSession,
    deleteChatSession
  } = useChatHistory();

  const handleSendMessage = async () => {
    if (inputMessage.trim()) {
      setShowSuggestions(false);
      await sendMessage();
    }
  };

  const handleSuggestionClick = (suggestion) => {
    setInputMessage(suggestion);
    setShowSuggestions(false);
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  useEffect(() => {
    // Auto-hide suggestions after first message
    if (messages.length > 1) {
      setShowSuggestions(false);
    }
  }, [messages]);

  return (
    <div className={`chat-interface ${theme}`} data-theme={theme}>
      {/* Mobile Header */}
      <div className="mobile-header">
        <button 
          className="sidebar-toggle"
          onClick={toggleSidebar}
          aria-label="Toggle sidebar"
        >
          <span className="hamburger-icon">
            <span></span>
            <span></span>
            <span></span>
          </span>
        </button>
        
        <div className="header-title">
          <span className="brand-icon">🤖</span>
          <span>StudyBuddy</span>
        </div>
        
        <button 
          className="theme-toggle"
          onClick={toggleTheme}
          aria-label="Toggle theme"
        >
          {theme === 'dark' ? '☀️' : '🌙'}
        </button>
      </div>

      {/* Sidebar */}
      <Sidebar 
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
        chatHistory={chatHistory}
        onLoadChat={loadChatSession}
        onDeleteChat={deleteChatSession}
        onNewChat={clearChat}
        currentSessionId={sessionId}
        theme={theme}
      />

      {/* Sidebar Overlay */}
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}

      {/* Main Chat Area */}
      <div className={`main-chat-area ${sidebarOpen ? 'sidebar-open' : ''}`}>
        {/* Desktop Header */}
        <div className="desktop-header">
          <div className="header-left">
            <button 
              className="sidebar-toggle desktop"
              onClick={toggleSidebar}
            >
              <span className="toggle-icon">
                {sidebarOpen ? '✕' : '☰'}
              </span>
            </button>
            <div className="header-title">
              <span className="brand-icon">🤖</span>
              <span>StudyBuddy - AI Academic Companion</span>
            </div>
          </div>
          
          <div className="header-right">
            <button 
              className="theme-toggle desktop"
              onClick={toggleTheme}
            >
              {theme === 'dark' ? '☀️ Light' : '🌙 Dark'}
            </button>
          </div>
        </div>

        {/* Messages Area */}
        <MessageArea 
          messages={messages}
          isTyping={isTyping}
          theme={theme}
        />

        {/* Suggestions (shown above input when active) */}
        {showSuggestions && messages.length <= 1 && (
          <SuggestionChips 
            onSuggestionClick={handleSuggestionClick}
            theme={theme}
          />
        )}

        {/* Input Area */}
        <InputArea
          inputMessage={inputMessage}
          setInputMessage={setInputMessage}
          onSendMessage={handleSendMessage}
          isLoading={isLoading}
          theme={theme}
          placeholder="Ask me anything about programming, math, science, or any subject! 🚀"
        />
      </div>
    </div>
  );
};

export default ChatContainer;
